# %%
# Select specific model here
model = "gemma3:1b"

# %%
from ollama import chat

response = chat(
    model = model,
    messages = [{"role": "user", 'content': "What can you help me with?"}]
)

print(response.message.content)

# %%
# May take 2-3 mins on first run, copied for reference
# from ollama import chat

# response = chat(
#     model = model,
#     messages = [{"role": "user", 'content': "What can you help me with?"}]
# )

# print(response.message.content)

# %%
def ChatWrapper(user_prompt: str, system_prompt: str = "", model: str="gemma3:1b", options={}):
  print("="*72)
  print("System Prompt:")
  print(system_prompt)
  print()
  print("User Input:\n", user_prompt)
  llm_response = chat(
      model = model,
      messages = [{"role": "system", "content": system_prompt}, {"role": "user", "content": user_prompt}],
      options = options
  ).message.content
  print()
  print("LLM Response:\n", llm_response)
  print("="*72)

# %%
ChatWrapper(
    user_prompt = "Create a haiku about programming",
    options = {"top_k": 5},
    model="gemma3:1b"
)

