# %% [markdown]
# ### 2.1.3 Chain-of-Thought (CoT)
# 
# For chain-of-thought prompting, we instruct the LLM to break down its step-by-step reasoning while answering.
# 
# This is analogous to expecting full solutions in an exam (instead of just jumping straight to the final answer), and can help reduce hallucination.

# %%
ChatWrapper(
  user_prompt = "This vacuum looks good at first but broke after 3 weeks, I hate it.",
  system_prompt = """
    Classify this review as positive, negative, or neutral.
    Reason out your answer step-by-step.
    You need to first identify sentiment words then apply their weights.
    The final step is to classify the overall user sentiment to positive, negative, or neutral.
    """,
  model = "gemma3:1b"
)

# %% [markdown]
# Let's try another example.

# %%
ChatWrapper(
  user_prompt = "This vacuum looks good at first but broke after 3 weeks, I don't mind. For the price point, I think it's fair and it did work.",
  system_prompt = """
    Classify this review as positive, negative, or neutral.
    Reason out your answer step-by-step.
    You need to first identify sentiment words then apply their weights.
    The final step is to classify the overall user sentiment to positive, negative, or neutral.
    """,
  model = "gemma3:1b"
)

