# %% [markdown]
# ### 2.3.4 Combined
# 
# We use JSON mode and provide more details for the schema that we want, esp. when there are edge cases that we need to handle.
# 

# %%
ChatWrapper(
  user_prompt = "I have been using this CleanPro-5000 vacuum cleaner recently. It's too pricey.",
  system_prompt = """Extract the following information using the schema below:
```json
{
  "item": "string" (this should be the item brand),
  "category": "string" (you can only pick between the categories: [work, play]),
  "issue": "string",
  "time_used": "string" (we need exact dates, if the date isn't exact use [undefined]),
  "discount_code": "option" [yes, no]
}
```
""",
  options = {'num_predict': 100}, # just to keep it brief
  model = "gemma3:1b"
)

